package com.example.myapplication

import android.content.Intent
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (intent?.action == Intent.ACTION_SEND) {
            val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
            val sharedImage = intent.getParcelableExtra(Intent.EXTRA_STREAM)

            if (sharedText != null) {
                // Handle shared text
                Toast.makeText(this, "Shared Text: $sharedText", Toast.LENGTH_SHORT).show()
            } else if (sharedImage != null) {
                // Handle shared image
                Toast.makeText(this, "Shared Image URI: $sharedImage", Toast.LENGTH_SHORT).show()
            }
        }

        finish()
    }
}